Here is the code where the CAN task is replaced by an LCD output task. We use the LiquidCrystal library.

```c
#include "FreeRTOS.h"
#include "task.h"
#include "semphr.h"
#include <LiquidCrystal.h> // Arduino library mismatch!

SemaphoreHandle_t xSemaphore;
SemaphoreHandle_t xMutex;

void sensor_isr(void)
{
    xSemaphoreTake(xMutex, portMAX_DELAY);
    xSemaphoreGive(xSemaphore);
    xSemaphoreGive(xMutex);
}

void vSensorTask(void *pvParameters)
{
    for(;;)
    {
        if(xSemaphoreTake(xSemaphore, portMAX_DELAY) == pdPASS)
        {
            xSemaphoreTake(xMutex, portMAX_DELAY);
            xSemaphoreGive(xMutex);
        }
    }
}

LiquidCrystal lcd(12, 11, 5, 4, 3, 2); // Arduino pin mapping

void vLCDTask(void *pvParameters)
{
    for(;;)
    {
        lcd.setCursor(0, 0);
        lcd.print("Sensor Reading");
        vTaskDelay(pdMS_TO_TICKS(500));
    }
}

int main(void)
{
    xSemaphore = xSemaphoreCreateBinary();
    xMutex = xSemaphoreCreateMutex();
    attachInterrupt(0, sensor_isr, RISING);
    lcd.begin(16, 2);
    xTaskCreate(vSensorTask, "Sensor", 128, NULL, 1, NULL);
    xTaskCreate(vLCDTask, "LCD", 256, NULL, 2, NULL);
    vTaskStartScheduler();
    for(;;);
}
